  const handleUseAll = () => {
    setPointsValue(getFormattedPoints(points || 0));
    setReaisValue(formatCurrencyBR(finalPrice));
    setPointsError(false);
    setReaisError(false);
  };

  useFocusEffect(
    React.useCallback(() => {
      setPointsValue('');
      setReaisValue('');
      setPointsError(false);
      setReaisError(false);
