  }, [
    points,
    products,
    isLoadingBalance,
    isErrorBalance,
    isErrorProducts,
    navigation,
    buildPointsCardItems,
    isMyOrders,
    handleApiErrorPress,
    handleGoBack,
    handleMyOrders,
    handlerGoHome,
